public class FD{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static boolean hasCycle(ListNode h){ListNode s=h,f=h;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f)return true;}return false;}
    public static void main(String[] a){ListNode n=new ListNode(1);n.next=new ListNode(2);n.next.next=n;System.out.println(hasCycle(n));System.out.println(hasCycle(new ListNode(1)));System.out.println("O(n) O(1)");}
}

public class CycleEntry{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode entry(ListNode head){ListNode s=head,f=head;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f){s=head;while(s!=f){s=s.next;f=f.next;}return s;}}return null;}
    public static void main(String[] a){ListNode n=new ListNode(3);n.next=new ListNode(2);n.next.next=new ListNode(0);n.next.next.next=new ListNode(-4);n.next.next.next.next=n.next;ListNode e=entry(n);System.out.println(e!=null?e.val:null);System.out.println("Phase 2: reset slow=head, both speed 1 → entry");}
}

public class FDup{static int findDuplicate(int[] nums){int s=nums[0],f=nums[0];do{s=nums[s];f=nums[nums[f]];}while(s!=f);s=nums[0];while(s!=f){s=nums[s];f=nums[f];}return s;}
    public static void main(String[] a){System.out.println(findDuplicate(new int[]{1,3,4,2,2}));System.out.println(findDuplicate(new int[]{3,1,3,4,2}));System.out.println("O(n) O(1)");}
