public class CLen{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static int cycleLen(ListNode h){ListNode s=h,f=h;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f){int len=1;ListNode t=s.next;while(t!=s){t=t.next;len++;}return len;}}return 0;}
    public static void main(String[] a){ListNode n=new ListNode(1);n.next=new ListNode(2);n.next.next=new ListNode(3);n.next.next.next=n;System.out.println(cycleLen(n));System.out.println(cycleLen(new ListNode(1)));System.out.println("O(n) O(1)");}
}

public class HNum{static int sq(int n){int s=0;while(n>0){int d=n%10;s+=d*d;n/=10;}return s;}
    static boolean isHappy(int n){int s=n,f=n;do{s=sq(s);f=sq(sq(f));}while(s!=f);return s==1;}
    public static void main(String[] a){System.out.println(isHappy(19));System.out.println(isHappy(2));System.out.println(isHappy(7));System.out.println("Floyd on digit-square sequence");}
}

public class Inter{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode inter(ListNode a,ListNode b){ListNode p=a,q=b;while(p!=q){p=(p==null?b:p.next);q=(q==null?a:q.next);}return p;}
    public static void main(String[] a){ListNode s=new ListNode(8);s.next=new ListNode(4);ListNode la=new ListNode(4);la.next=new ListNode(1);la.next.next=s;ListNode lb=new ListNode(5);lb.next=s;System.out.println(inter(la,lb).val);System.out.println("O(n+m) O(1)");}
}

