import java.util.*;
public class GraphCycle{static boolean hasCycle(int n,int[][] edges){List<List<Integer>> adj=new ArrayList<>();for(int i=0;i<n;i++)adj.add(new ArrayList<>());for(int[] e:edges)adj.get(e[0]).add(e[1]);int[] state=new int[n]; // 0=unvisited,1=visiting,2=done
    for(int i=0;i<n;i++)if(state[i]==0&&dfs(adj,state,i))return true;return false;}
    static boolean dfs(List<List<Integer>> adj,int[] state,int node){state[node]=1;for(int nb:adj.get(node)){if(state[nb]==1)return true;if(state[nb]==0&&dfs(adj,state,nb))return true;}state[node]=2;return false;}
    public static void main(String[] a){System.out.println(hasCycle(4,new int[][]{{0,1},{1,2},{2,3},{3,1}}));System.out.println(hasCycle(4,new int[][]{{0,1},{1,2},{2,3}}));System.out.println("DFS cycle detection in graph");}
}

public class ThreePhase{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static void main(String[] a){ListNode n=new ListNode(1);n.next=new ListNode(2);n.next.next=new ListNode(3);n.next.next.next=new ListNode(4);n.next.next.next.next=n.next; // cycle to 2
    // Phase 1:
    ListNode s=n,f=n;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f)break;}System.out.println("Phase1 met at: "+s.val);
    // Phase 2:
    s=n;while(s!=f){s=s.next;f=f.next;}System.out.println("Cycle entry: "+s.val);
    // Phase 3:
    int len=1;ListNode t=s.next;while(t!=s){t=t.next;len++;}System.out.println("Cycle length: "+len);}
}

