public class FuncCycle{static int next(int x){return (x*x+1)%100;}
    static int findCycleStart(int start){int s=start,f=start;do{s=next(s);f=next(next(f));}while(s!=f);s=start;while(s!=f){s=next(s);f=next(f);}return s;}
    public static void main(String[] a){System.out.println("Cycle entry for start=0: "+findCycleStart(0));System.out.println("Cycle entry for start=50: "+findCycleStart(50));System.out.println("Floyd works on any functional sequence, not just linked lists!");}
}

public class FullCycle{static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    record CycleInfo(boolean hasCycle,int entryVal,int length){}
    static CycleInfo analyze(ListNode head){ListNode s=head,f=head;while(f!=null&&f.next!=null){s=s.next;f=f.next.next;if(s==f){int len=1;ListNode t=s.next;while(t!=s){t=t.next;len++;}s=head;while(s!=f){s=s.next;f=f.next;}return new CycleInfo(true,s.val,len);}}return new CycleInfo(false,-1,0);}
    public static void main(String[] a){ListNode n=new ListNode(1);n.next=new ListNode(2);n.next.next=new ListNode(3);n.next.next.next=n.next;CycleInfo c=analyze(n);System.out.println(c);System.out.println("All 3 phases in one function — O(n) O(1)");}
}

